import{_ as t,o as d,c as r,a3 as o}from"./chunks/framework.DG2GXa4n.js";const u=JSON.parse('{"title":"vs. farfetched","description":"","frontmatter":{},"headers":[],"relativePath":"guide/vs-farfetched.md","filePath":"guide/vs-farfetched.md","lastUpdated":1781015796000}'),a={name:"guide/vs-farfetched.md"};function c(s,e,n,i,f,l){return d(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="vs-farfetched" tabindex="-1">vs. farfetched <a class="header-anchor" href="#vs-farfetched" aria-label="Permalink to &quot;vs. farfetched&quot;">​</a></h1><p><a href="https://ff.effector.dev" target="_blank" rel="noreferrer">farfetched</a> is the most complete data-fetching tool for effector and the obvious reference point. It is <strong>open-source and not archived</strong> — but its cadence has slowed: it is still pre-1.0, the original &quot;1.0 by end of 2024&quot; target has slipped, and the issue backlog keeps growing. <code>effector-refetch</code> exists to be the <strong>maintained, effect-first</strong> option with a smaller, friendlier surface — not to claim farfetched is dead.</p><table tabindex="0"><thead><tr><th></th><th>farfetched</th><th>effector-refetch</th></tr></thead><tbody><tr><td>unit of work</td><td>internal event-based executor</td><td>your real <code>Effect</code> — first-class</td></tr><tr><td>primary input</td><td><code>handler</code> (wrapped); <code>effect</code> is one path</td><td><code>effect</code> is the main input; <code>handler</code> is sugar</td></tr><tr><td>retry / cache / concurrency</td><td>separate operators</td><td>inline options <strong>and</strong> standalone operators</td></tr><tr><td>sourced config</td><td>sourced fields</td><td>reactive <code>Store</code> for <code>enabled</code> / <code>concurrency</code> / <code>retry.times</code> / <code>cache.staleAfter</code></td></tr><tr><td>validation</td><td><code>contract</code>, <code>validate</code></td><td><code>contract</code> (zod / Standard Schema) + <code>validate</code></td></tr><tr><td>declarative HTTP</td><td><code>createJsonQuery</code></td><td><code>createJsonQuery</code> (global <code>fetch</code>, zero deps)</td></tr><tr><td>pagination</td><td>—</td><td><code>createInfiniteQuery</code></td></tr><tr><td>cancellation</td><td>abort + discard</td><td>real <code>AbortSignal</code> via <code>createRequestFx</code></td></tr><tr><td>bindings</td><td>react / solid / vue</td><td><code>useUnit(query)</code> (react + vue) + <code>useQuery</code> helpers</td></tr></tbody></table><p><strong>Honest trade-off.</strong> farfetched still ships more in some areas (sourced everything, JSON contracts ecosystem, maturity). <code>effector-refetch</code> is simpler, closer to bare effector (&quot;I already have an effect, wrap it&quot;), and intends to reach a stable 1.0. If you need farfetched&#39;s full surface today, use it; if you want an effect-first API on a maintained project, use this.</p>',4)])])}const p=t(a,[["render",c]]);export{u as __pageData,p as default};
